import argparse
import json
import random
import socket
import threading
import time
from typing import Dict, List, Tuple

MAX_DATAGRAM_SIZE = 65507
DEFAULT_HOST = "0.0.0.0"
DEFAULT_PORT = 27015
QUERY_STATUS = b"\xFF\xFF\xFF\xFFstatus"
RESPONSE_PREFIX = b"\xFF\xFF\xFF\xFFstatusResponse\n"


class GameState:
    def __init__(self) -> None:
        self._lock = threading.Lock()
        self.server_name = "Example Game Server"
        self.map_name = "arena_01"
        self.game_mode = "deathmatch"
        self.max_players = 64
        self.tick_rate = 60
        self.version = "1.0.0"
        self.start_time = time.time()
        self.players = self._generate_players(24)

    def _generate_players(self, count: int) -> List[Dict]:
        names = [
            "Alpha", "Bravo", "Charlie", "Delta", "Echo", "Foxtrot", "Ghost", "Hunter",
            "Icarus", "Jester", "Kilo", "Lancer", "Mantis", "Nova", "Orion", "Phantom",
            "Quasar", "Ranger", "Spectre", "Titan", "Umbra", "Viper", "Warden", "Zephyr",
            "Atlas", "Blaze", "Cipher", "Drift", "Ember", "Falcon", "Glitch", "Havoc",
            "Inferno", "Jaguar", "Kraken", "Lynx", "Mirage", "Nomad", "Onyx", "Pulse",
        ]
        random.shuffle(names)
        players = []
        for i in range(count):
            players.append({
                "id": i + 1,
                "name": names[i % len(names)],
                "score": random.randint(0, 100),
                "ping": random.randint(15, 180),
                "team": random.choice(["red", "blue", "spectator"]),
                "alive": random.choice([True, False]),
                "time_connected_sec": random.randint(30, 7200),
            })
        return players

    def snapshot(self) -> Dict:
        with self._lock:
            uptime = int(time.time() - self.start_time)
            return {
                "server_name": self.server_name,
                "map": self.map_name,
                "game_mode": self.game_mode,
                "version": self.version,
                "tick_rate": self.tick_rate,
                "uptime_sec": uptime,
                "player_count": len(self.players),
                "max_players": self.max_players,
                "state": {
                    "round": random.randint(1, 20),
                    "time_remaining_sec": random.randint(10, 900),
                    "friendly_fire": random.choice([True, False]),
                    "ranked": random.choice([True, False]),
                    "vac_enabled": True,
                },
                "players": list(self.players),
            }

    def mutate_loop(self) -> None:
        while True:
            time.sleep(5)
            with self._lock:
                for p in self.players:
                    p["score"] += random.randint(0, 3)
                    p["ping"] = max(5, min(250, p["ping"] + random.randint(-10, 10)))
                    p["alive"] = random.choice([True, False])
                    p["time_connected_sec"] += 5
                if self.players and random.random() < 0.2:
                    random.choice(self.players)["team"] = random.choice(["red", "blue", "spectator"])


class UDPGameServer:
    def __init__(self, host: str, port: int, game_state: GameState) -> None:
        self.host = host
        self.port = port
        self.game_state = game_state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        try:
            self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1 << 20)
            self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1 << 20)
        except OSError:
            pass

    def build_status_response(self) -> bytes:
        payload = json.dumps(self.game_state.snapshot(), separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        response = RESPONSE_PREFIX + payload
        if len(response) > MAX_DATAGRAM_SIZE:
            trimmed = {
                "error": "response_too_large",
                "max_datagram_size": MAX_DATAGRAM_SIZE,
                "actual_size": len(response),
            }
            response = RESPONSE_PREFIX + json.dumps(trimmed, separators=(",", ":")).encode("utf-8")
        return response

    def serve_forever(self) -> None:
        self.sock.bind((self.host, self.port))
        print(f"UDP game server listening on {self.host}:{self.port}")
        while True:
            data, addr = self.sock.recvfrom(8192)
            if data.startswith(QUERY_STATUS):
                response = self.build_status_response()
                self.sock.sendto(response, addr)

    def close(self) -> None:
        self.sock.close()


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default=DEFAULT_HOST)
    parser.add_argument("--port", type=int, default=DEFAULT_PORT)
    args = parser.parse_args()

    game_state = GameState()
    threading.Thread(target=game_state.mutate_loop, daemon=True).start()

    server = UDPGameServer(args.host, args.port, game_state)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        server.close()


if __name__ == "__main__":
    main()